+impl MermaidComplexity {
+    #[must_use]
+    pub fn from_counts(
+        nodes: usize,
+        edges: usize,
+        labels: usize,
+        clusters: usize,
+        ports: usize,
+        style_refs: usize,
+    ) -> Self {
+        let score = nodes
+            .saturating_add(edges)
+            .saturating_add(labels)
+            .saturating_add(clusters);
+        Self {
+            nodes,
+            edges,
+            labels,
+            clusters,
+            ports,
+            style_refs,
+            score,
+        }
+    }
