+
+impl LabelInterner {
+    fn intern(&mut self, text: &str, span: Span) -> IrLabelId {
+        if let Some(id) = self.index.get(text).copied() {
+            return id;
+        }
+        let id = IrLabelId(self.labels.len());
+        self.labels.push(IrLabel {
+            text: text.to_string(),
+            span,
+        });
+        self.index.insert(text.to_string(), id);
+        id
     }
