+    edge_drafts.sort_by(|a, b| {
+        (
+            a.from.as_str(),
+            a.from_port.as_deref().unwrap_or(""),
+            a.to.as_str(),
+            a.to_port.as_deref().unwrap_or(""),
+            a.span.start.line,
+            a.span.start.col,
+            a.insertion_idx,
+        )
+            .cmp(&(
+                b.from.as_str(),
+                b.from_port.as_deref().unwrap_or(""),
+                b.to.as_str(),
+                b.to_port.as_deref().unwrap_or(""),
+                b.span.start.line,
+                b.span.start.col,
